using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace ApiMcpServer.Tools;

/// <summary>
/// MCP tools that wrap a REST API (Open-Meteo weather API in this example).
/// Uses constructor injection — the SDK resolves HttpClient and ILogger
/// automatically because they are registered in the DI container.
/// </summary>
[McpServerToolType]
public class WeatherApiTools(HttpClient httpClient, ILogger<WeatherApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("Get the current weather for a location by latitude and longitude.")]
    public async Task<string> GetCurrentWeather(
        [Description("Latitude of the location (e.g. 47.6)")] double latitude,
        [Description("Longitude of the location (e.g. -122.3)")] double longitude,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching weather for ({Lat}, {Lon})", latitude, longitude);

        var url = $"https://api.open-meteo.com/v1/forecast"
                + $"?latitude={latitude}&longitude={longitude}"
                + "&current=temperature_2m,wind_speed_10m";

        var response = await httpClient.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();

        using var doc = await JsonDocument.ParseAsync(
            await response.Content.ReadAsStreamAsync(cancellationToken), cancellationToken: cancellationToken);

        return JsonSerializer.Serialize(doc.RootElement.GetProperty("current"), JsonOptions);
    }

    [McpServerTool, Description("Get a multi-day weather forecast for a location.")]
    public async Task<string> GetForecast(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude,
        [Description("Number of forecast days (1-16)")] int days = 7,
        CancellationToken cancellationToken = default)
    {
        days = Math.Clamp(days, 1, 16);
        logger.LogInformation("Fetching {Days}-day forecast for ({Lat}, {Lon})", days, latitude, longitude);

        var url = $"https://api.open-meteo.com/v1/forecast"
                + $"?latitude={latitude}&longitude={longitude}"
                + $"&daily=temperature_2m_max,temperature_2m_min&forecast_days={days}";

        var response = await httpClient.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();

        using var doc = await JsonDocument.ParseAsync(
            await response.Content.ReadAsStreamAsync(cancellationToken), cancellationToken: cancellationToken);

        return JsonSerializer.Serialize(doc.RootElement.GetProperty("daily"), JsonOptions);
    }
}

